const res = $input.first().json;
const rows = res.values || [];

let batchIndex = 0;
try {
  const wh = $('Stage1 Self-Chain Webhook').first().json;
  const body = wh.body || wh;
  batchIndex = parseInt(body.batch_index) || 0;
} catch (e) {}

let pendingRows = [];
for (let i = 0; i < rows.length; i++) {
  const s = (rows[i][11] || '').toString().trim().toUpperCase();
  if (s === 'NOT STARTED') { pendingRows.push({ idx: i, row: rows[i] }); }
}
if (pendingRows.length === 0) {
  return [{ json: { stop: true, reason: 'NO_NOT_STARTED_TOPICS', batch_index: batchIndex } }];
}
const found = pendingRows[Math.floor(Math.random() * pendingRows.length)];
const sheetRow = found.idx + 4;
return [{
  json: {
    stop: false,
    batch_index: batchIndex,
    job_id:             (found.row[0] || '').trim() || ('PHY-' + Date.now().toString().slice(-8)),
    topic:              (found.row[1] || '').trim(),
    category:           (found.row[2] || '').trim(),
    core_theory:        (found.row[3] || '').trim(),
    scientific_depth:   (found.row[4] || '').trim(),
    hook_line:          (found.row[5] || '').trim(),
    narrative_angle:    (found.row[6] || '').trim(),
    visual_suggestions: (found.row[7] || '').trim(),
    target_audience:    (found.row[8] || '').trim(),
    post_format:        (found.row[9] || '').trim(),
    difficulty:         (found.row[10] || 'advanced').trim(),
    duration_min:       0.25,
    sheet_row:          sheetRow,
    source:             'google_sheet'
  }
}];

const raw       = $input.first().json;
const body      = (raw.body !== undefined) ? raw.body : raw;

let sheetData = {};
try { sheetData = $('Pick Approved Topic').first().json; } catch(e) {}

const jobId      = body.job_id      || raw.job_id      || sheetData.job_id      || ('PHY-' + Date.now().toString().slice(-8));
const topic      = body.topic       || raw.topic       || sheetData.topic;
const sheetRow   = body.sheet_row   || raw.sheet_row   || sheetData.sheet_row   || null;
const difficulty = body.difficulty  || raw.difficulty  || sheetData.difficulty  || 'advanced';
const durationMin = parseFloat(body.duration_min || raw.duration_min || sheetData.duration_min) || 0.333;

if (!topic) throw new Error('No topic found. Check Google Sheet.');

const durationSec = Math.round(durationMin * 60);
const numClips    = Math.min(4, Math.max(2, Math.ceil(durationSec / 5)));
const wordTarget  = Math.min(36, Math.max(18, Math.round(durationSec * 1.7)));

return [{ json: {
  ...sheetData,
  job_id: jobId, topic, difficulty, sheet_row: sheetRow,
  duration_min: durationMin, duration_sec: durationSec,
  num_clips: numClips, word_target: wordTarget,
  start_time: Date.now()
}}];

const response  = $input.first().json;
const jobConfig = $('Set Job Config').first().json;
const expectedClips = jobConfig.num_clips || 6;

if (!response.content || !response.content[0] || !response.content[0].text)
  throw new Error('Claude response empty: ' + JSON.stringify(response).slice(0, 300));

let rawText = response.content[0].text.trim();
rawText = rawText.replace(/^```(?:json)?\s*/i, '').replace(/\s*```\s*$/i, '').trim();

let parsed;
try { parsed = JSON.parse(rawText); }
catch(e) {
  const s = rawText.indexOf('{'), endIndex = rawText.lastIndexOf('}');
  parsed = JSON.parse((s !== -1 && endIndex !== -1) ? rawText.slice(s, endIndex+1) : rawText);
}

if (!parsed.scenes || !Array.isArray(parsed.scenes))
  throw new Error('Claude returned no scenes array');

// Strict scene count validation
if (parsed.scenes.length !== expectedClips) {
  console.warn('Claude returned ' + parsed.scenes.length + ' scenes, expected ' + expectedClips + '. Fixing...');
  if (parsed.scenes.length < expectedClips) {
    // Pad missing scenes by duplicating the last scene with adjusted timing
    while (parsed.scenes.length < expectedClips) {
      const i = parsed.scenes.length;
      const last = parsed.scenes[parsed.scenes.length - 1];
      parsed.scenes.push({
        ...last,
        scene_number: i + 1,
        start_sec: i * 5,
        end_sec: (i + 1) * 5,
        narration_segment: last.narration_segment
      });
    }
  } else {
    // Trim extra scenes
    parsed.scenes = parsed.scenes.slice(0, expectedClips);
  }
}

console.log('Scenes validated: ' + parsed.scenes.length + ' scenes for ' + jobConfig.duration_sec + 's video');

const clip_prompts    = parsed.scenes.map(s => s.visual_prompt);
const negative_prompts = parsed.scenes.map(s => s.negative_prompt || 'text, letters, numbers, labels, watermarks, UI, human faces, cartoon, anime, blurry, low quality');

return [{ json: {
  ...jobConfig,
  narration:       parsed.narration,
  scenes:          parsed.scenes,
  clip_prompts,
  negative_prompts,
  title:           parsed.title    || jobConfig.topic,
  hashtags:        parsed.hashtags || '#physics #science',
  social_caption:  parsed.social_caption || '',
  highlight_keywords: parsed.highlight_keywords || []
}}];

const fs           = require('fs');
const { execSync } = require('child_process');

const data  = $input.first().json;
const jobId = data.job_id;
const clips = (data.clip_prompts || []);

const clipCount = clips.length;
const CLIP_DUR  = 5.0;
const FADE_DUR  = 0.3;
const videoDuration = clipCount > 0
  ? (clipCount * CLIP_DUR - Math.max(0, clipCount - 1) * FADE_DUR)
  : 20;

// Pick a random BGM via docker exec (avoids n8n filesystem path issues).
const bgmContDir = '/ffmpeg/config/bgm_aperture';
const lsOut = execSync('docker exec phys_ffmpeg_runner ls ' + bgmContDir, { encoding: 'utf-8', timeout: 10000 });
const bgmFiles = lsOut.trim().split('\n').filter(f => f.trim().endsWith('.mp3'));
if (bgmFiles.length === 0) throw new Error('No mp3 files found in ' + bgmContDir);
const bgmLibPath = bgmContDir + '/' + bgmFiles[Math.floor(Math.random() * bgmFiles.length)].trim();
const bgmN8nPath  = '/data/ffmpeg/input/' + jobId + '_bgm.mp3';
const bgmContPath = '/ffmpeg/input/'      + jobId + '_bgm.mp3';

// Trim (no loop) + fade to video duration. If BlipStream.mp3 is shorter
// than the video, it simply ends early â€” it is never repeated.
const fadeOutStart = Math.max(0, videoDuration - 1.5);
const trimCmd =
  'docker exec phys_ffmpeg_runner ffmpeg -y ' +
  '-i "' + bgmLibPath + '" ' +
  '-t ' + videoDuration.toFixed(3) + ' ' +
  '-af "afade=t=in:st=0:d=1.5,afade=t=out:st=' + fadeOutStart.toFixed(3) + ':d=1.5,volume=0.3" ' +
  '-acodec libmp3lame -ab 128k ' +
  '"' + bgmContPath + '" 2>&1 && echo TRIM_OK';

console.log('BGM: ' + bgmLibPath + ' | duration: ' + videoDuration.toFixed(1) + 's');
const trimResult = execSync(trimCmd, { encoding: 'utf-8', timeout: 30000 });
if (!trimResult.includes('TRIM_OK')) throw new Error('BGM trim failed: ' + trimResult.slice(-300));

console.log('BGM ready: ' + bgmN8nPath);

return [{ json: {
  ...data,
  audio_path:      null,
  subs_path:       null,
  audio_duration:  videoDuration,
  subtitle_chunks: [],
  word_timings:    [],
  word_count:      0,
  bgm_path:        bgmN8nPath
}}];

const d = $input.first().json;
const sheetId = '1VD-F6Wj47Dm_5Uo_zdIEuxOnqprepCPRTKEmTYs6mFs';
const sheetName = 'Video%20Production%20Queue';

// Find next empty row by reading full A:L range (avoids append landing at wrong column)
const readResp = await this.helpers.httpRequestWithAuthentication.call(
  this, 'googleSheetsOAuth2Api',
  {
    method: 'GET',
    url: `https://sheets.googleapis.com/v4/spreadsheets/${sheetId}/values/${sheetName}!A:L`,
  }
);
const existingRows = (readResp.values || []);
const nextRow = existingRows.length + 1;

// PUT to exact row so data always lands in column A (not F like append was doing)
await this.helpers.httpRequestWithAuthentication.call(
  this, 'googleSheetsOAuth2Api',
  {
    method: 'PUT',
    url: `https://sheets.googleapis.com/v4/spreadsheets/${sheetId}/values/${sheetName}!A${nextRow}:L${nextRow}?valueInputOption=RAW`,
    body: {
      majorDimension: 'ROWS',
      values: [[
        d.job_id, d.topic, d.title, 'READY_FOR_VIDEO',
        d.payload_json, '', '', d.hashtags,
        d.sheet_row, d.readyForVideoAt || new Date().toISOString(), '', ''
      ]]
    },
    json: true,
  }
);

console.log('Appended job', d.job_id, 'to row', nextRow);
const updatedRange = `'Video Production Queue'!A${nextRow}:L${nextRow}`;
return [{ json: {
  spreadsheetId: sheetId,
  tableRange: updatedRange,
  updates: {
    spreadsheetId: sheetId,
    updatedRange: updatedRange,
    updatedRows: 1,
    updatedColumns: 12,
    updatedCells: 12
  }
}}];

const researchResp = $input.first().json;
const jobData = $('Set Job Config').first().json;
let researchText = '';
try {
  researchText = researchResp.content[0].text || '';
} catch(e) {
  researchText = 'No research available.';
}
console.log('Research obtained: ' + researchText.slice(0, 100) + '...');
return [{ json: { ...jobData, topic_research: researchText } }];

const data = $input.first().json;
console.log('Stage 1 drain finished. Reason: ' + data.reason);
return [{ json: { summary: 'stage1_idle', ...data } }];

const http = require('http');

const row   = $('Build Video Queue Row').item.json;
const extra = JSON.parse(row.payload_json || '{}');

// Extract queue row index from Append to Video Queue response
let queueRowIndex = null;
try {
  const appendRes = $('Append to Video Queue').item.json;
  const updRange  = (appendRes.updates && appendRes.updates.updatedRange) || '';
  const m = updRange.match(/[A-Z]+(\d+):/);
  if (m) queueRowIndex = parseInt(m[1]);
} catch(e) { console.log('queue row index not found:', e.message); }

const payload = {
  job_id:             row.job_id,
  topic:              row.topic,
  title:              row.title,
  hashtags:           row.hashtags,
  sheet_row:          row.sheet_row,
  queue_row_index:    queueRowIndex,
  narration:          extra.narration || '',
  clip_prompts:       extra.clip_prompts || [],
  audio_path:         extra.audio_path || null,
  subs_path:          extra.subs_path  || null,
  audio_duration:     extra.audio_duration || 19.1,
  subtitle_chunks:    extra.subtitle_chunks || [],
  word_timings:       extra.word_timings || [],
  bgm_path:           extra.bgm_path || null,
  negative_prompts:   extra.negative_prompts || [],
  highlight_keywords: extra.highlight_keywords || [],
  scenes:             extra.scenes || [],
  readyForVideoAt:    row.readyForVideoAt,
  start_time:         Date.now()
};

const body = JSON.stringify(payload);
await new Promise((res, rej) => {
  const req = http.request({
    hostname:'localhost', port:5679,
    path:'/webhook/stage2-video', method:'POST',
    headers:{'Content-Type':'application/json','Content-Length':Buffer.byteLength(body)}
  }, r => { let d=''; r.on('data',c=>d+=c); r.on('end',()=>res(d)); });
  req.on('error', rej);
  req.write(body); req.end();
});

console.log('Stage 2 triggered. queue_row_index:', queueRowIndex);
return [{ json: { ...payload, stage2_triggered: true } }];
